func siget_random_fd(cgtls *iqlibc.ppTLS) (cgr ppint32) {
	cgbp := cgtls.ppAlloc(16)
	defer cgtls.ppFree(16)

	var aai ppint32
	var pp_ /* tv at bp+0 */ tstimeval
	pp_ = aai
	var snfd = -ppint32(2)

	if snfd == -ppint32(2) {
		Xgettimeofday(cgtls, cgbp, ppuintptr(0))
		snfd = Xopen(cgtls, "/dev/urandom\x00", mvO_RDONLY, 0)
		if snfd == -ppint32(1) {
			snfd = Xopen(cgtls, "/dev/random\x00", iqlibc.ppInt32FromInt32(mvO_RDONLY)|iqlibc.ppInt32FromInt32(mvO_NONBLOCK), 0)
		}
		/* go2fs: fcntl removed - Xfcntl64 not implemented in
		   modernc/libc on darwin/arm64. FD_CLOEXEC is not
		   essential for image-file filesystem creation. */
		/* if (fd >= 0) {
			i = fcntl(fd, F_GETFD);
			if (i >= 0)
				fcntl(fd, F_SETFD, i | FD_CLOEXEC);
		} */
		Xsrandom(cgtls, iqlibc.ppUint32FromInt64(iqlibc.ppInt64FromUint32(iqlibc.ppUint32FromInt32(Xgetpid(cgtls))<<ppint32(16)^Xgetuid(cgtls))^(*(*tstimeval)(iqunsafe.ppPointer(cgbp))).fdtv_sec^ppint64((*(*tstimeval)(iqunsafe.ppPointer(cgbp))).fdtv_usec)))
	}
	/* Crank the random number generator a few times */
	Xgettimeofday(cgtls, cgbp, ppuintptr(0))
	aai = ppint32(((*(*tstimeval)(iqunsafe.ppPointer(cgbp))).fdtv_sec ^ ppint64((*(*tstimeval)(iqunsafe.ppPointer(cgbp))).fdtv_usec)) & ppint64(0x1F))
	for {
		if !(aai > 0) {
			break
		}
		Xrandom(cgtls)
		goto cg_1
	cg_1:
		;
		aai = aai - 1
	}
	return snfd
}

// C documentation
//
//	/*
//	 * Generate a series of random bytes.  Use /dev/urandom if possible,
//	 * and if not, use srandom/random.
//	 */
func siget_random_bytes(cgtls *iqlibc.ppTLS, aabuf ppuintptr, aanbytes ppint32) {

	var aacp, ccv3, ccv4 ppuintptr
	var aafd, aai, aalose_counter, aan, ccv1 ppint32
	pp_, pp_, pp_, pp_, pp_, pp_, pp_, pp_ = aacp, aafd, aai, aalose_counter, aan, ccv1, ccv3, ccv4
	aan = aanbytes
	aalose_counter = 0
	aacp = aabuf

	if Xgetentropy(cgtls, aabuf, iqlibc.ppUint64FromInt32(aanbytes)) == 0 {
		return
	}

	aafd = siget_random_fd(cgtls)
	if aafd >= 0 {
		for aan > 0 {
			aai = ppint32(Xread(cgtls, aafd, aacp, iqlibc.ppUint64FromInt32(aan)))
			if aai <= 0 {
				ccv1 = aalose_counter
				aalose_counter = aalose_counter + 1
				if ccv1 > ppint32(16) {
					break
				}
				continue
			}
			aan = aan - aai
			aacp = aacp + ppuintptr(aai)
			aalose_counter = 0
		}
	}

	/*
	 * We do this all the time, but this is the only source of
	 * randomness if /dev/random/urandom is out to lunch.
	 */
	aacp = aabuf
	aai = iqlibc.ppInt32FromInt32(0)
	for {
		if !(aai < aanbytes) {
			break
		}
		ccv4 = aacp
		aacp = aacp + 1
		ccv3 = ccv4
		*(*ppuint8)(iqunsafe.ppPointer(ccv3)) = ppuint8(ppint64(*(*ppuint8)(iqunsafe.ppPointer(ccv3))) ^ Xrandom(cgtls)>>iqlibc.ppInt32FromInt32(7)&iqlibc.ppInt64FromInt32(0xFF))
		goto cg_2
	cg_2:
		;
		aai = aai + 1
	}

	return
}

// C documentation
//
//	/*
//	 * Get the ethernet hardware address, if we can find it...
//	 *
//	 * XXX for a windows version, probably should use GetAdaptersInfo:
//	 * http://www.codeguru.com/cpp/i-n/network/networkinformation/article.php/c5451
//	 * commenting out get_node_id just to get gen_uuid to compile under windows
//	 * is not the right way to go!
